import{_ as o,o as r,c as e,af as a}from"./chunks/framework.BSym9njW.js";const l="data:image/webp;base64,",n="/hello-rocm/assets/08-six-benefits.BM8kICY5.webp",i="/hello-rocm/assets/01-login-methods.CUVdFm9Z.webp",s="/hello-rocm/assets/02-login-methods-alt.C1cpJoro.webp",d="/hello-rocm/assets/03-profile-points.CPBE3MSI.webp",h="/hello-rocm/assets/04-enter-cloud.DYQUouY_.webp",g="/hello-rocm/assets/05-workspace-templates.cZC50mKD.webp",c="/hello-rocm/assets/06-points-exchange.BsQ2-lPC.webp",m="/hello-rocm/assets/07-modelscope-paths.mkhnr7jB.webp",p="/hello-rocm/assets/01-convert.CjEuhiEy.webp",u="/hello-rocm/assets/02-convert.kOL2VTJq.webp",f="/hello-rocm/assets/03-convert.CUPGmAdN.webp",v=JSON.parse('{"title":"AMD Radeon Cloud","description":"AMD Radeon Cloud 云算力平台使用教程与登录入口","frontmatter":{"title":"AMD Radeon Cloud","description":"AMD Radeon Cloud 云算力平台使用教程与登录入口"},"headers":[],"relativePath":"zh/cloud/amd-radeon-cloud.md","filePath":"zh/cloud/amd-radeon-cloud.md","lastUpdated":1782210628000}'),A={name:"zh/cloud/amd-radeon-cloud.md"};function b(R,t,k,D,P,q){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="☁️-amd-radeon-cloud-·-云算力" tabindex="-1">☁️ AMD Radeon Cloud · 云算力 <a class="header-anchor" href="#☁️-amd-radeon-cloud-·-云算力" aria-label="Permalink to &quot;☁️ AMD Radeon Cloud · 云算力&quot;">​</a></h1><blockquote><p><strong>AMD 官方为中国开发者提供的免费 GPU 云算力平台</strong>，无需本地环境，浏览器登录即可上手 ROCm 实战。</p></blockquote><h2 id="🚀-立即体验" tabindex="-1">🚀 立即体验 <a class="header-anchor" href="#🚀-立即体验" aria-label="Permalink to &quot;🚀 立即体验&quot;">​</a></h2><div align="center"><p><a href="https://developer.amd.com.cn/login?source=91kadjjnI" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/%F0%9F%9A%80_AMD_Radeon_Cloud-立即登录-ed1941?logo=amd&amp;logoColor=white&amp;labelColor=1a1a1a&amp;style=for-the-badge" height="44"></a></p><br><img src="'+l+'" alt="扫码登录 AMD Radeon Cloud" width="200"><p><strong>📱 微信 / 浏览器扫码直达</strong></p><p>🔗 <a href="https://developer.amd.com.cn/login?source=91kadjjnI" target="_blank" rel="noreferrer">https://developer.amd.com.cn/login?source=91kadjjnI</a></p></div><h2 id="平台简介" tabindex="-1">平台简介 <a class="header-anchor" href="#平台简介" aria-label="Permalink to &quot;平台简介&quot;">​</a></h2><p><strong>AMD Radeon Cloud</strong> 是 <strong>AMD AI 开发者计划中文站</strong>（中国区官方平台）为开发者提供的云端算力入口。平台围绕 AMD 开源 AI 生态打造，目标是让中国本土开发者获得「无门槛、无网速焦虑」的原生 AMD 体验。</p><p><strong>核心特点</strong>：</p><ul><li>🇨🇳 <strong>本地化部署</strong>：中国区官方平台，免去访问与登录的网络障碍</li><li>☁️ <strong>免费算力额度</strong>：注册即送 <strong>100 小时</strong>中国区专属算力（活动期间）</li><li>🖥 <strong>底层硬件</strong>：基于 <strong>AMD Radeon PRO W7900D</strong> 等专业级 GPU 构建</li><li>📦 <strong>开箱即用</strong>：内置技术模板与预配置工作区，无需自行搭建环境</li><li>⭐ <strong>积分体系</strong>：完善信息、活跃贡献可累积积分，等额兑换算力券</li><li>🤝 <strong>进阶通道</strong>：通过魔搭社区联动「开发者激励计划」，最高可累计获得 <strong>1000+ 小时</strong> GPU 算力</li><li>💬 <strong>官方技术支持</strong>：中国成员专属微信群，AMD 官方团队解答 ROCm 与硬件适配问题</li></ul><p>加入 AMD AI 开发者计划中文站，成员将围绕技术、资源、交流三大维度，解锁完整的本地化服务版图：</p><div align="center"><img src="'+n+'" alt="6 大核心权益总览"></div><h2 id="平台使用教程" tabindex="-1">平台使用教程 <a class="header-anchor" href="#平台使用教程" aria-label="Permalink to &quot;平台使用教程&quot;">​</a></h2><p>完整流程：<strong>注册登录 → 完善信息（领取 100 积分）→ 进入 Radeon Cloud → 选择模板 / 创建工作区 → 开始实战</strong>。</p><h3 id="_1-注册与登录" tabindex="-1">1. 注册与登录 <a class="header-anchor" href="#_1-注册与登录" aria-label="Permalink to &quot;1. 注册与登录&quot;">​</a></h3><p>打开 <a href="https://developer.amd.com.cn/login?source=91kadjjnI" target="_blank" rel="noreferrer">https://developer.amd.com.cn/login?source=91kadjjnI</a>，中文站全面接入了国内主流账号体系，提供 <strong>3 种登录方式</strong>：</p><table tabindex="0"><thead><tr><th>方式</th><th>操作</th><th>适用场景</th></tr></thead><tbody><tr><td>🟢 <strong>微信登录</strong></td><td>扫描页面二维码</td><td>最快捷，一键直达</td></tr><tr><td>🤖 <strong>魔搭社区账号</strong></td><td>授权绑定已有账号</td><td>已有魔搭生态账号的开发者</td></tr><tr><td>📱 <strong>手机号 / 邮箱验证码</strong></td><td>输入接收验证码</td><td>灵活适配个人习惯</td></tr></tbody></table><div align="center"><img src="'+i+'" alt="3 种登录方式入口"></div><blockquote><p>💡 推荐使用微信登录，节省注册成本。</p></blockquote><p><strong>首次登录会跳转注册表单</strong>，按提示填写姓名、邮箱 / 手机号并完成验证：</p><div align="center"><img src="'+s+'" alt="AMD AI 开发者计划注册表单"></div><h3 id="_2-完善信息领取积分" tabindex="-1">2. 完善信息领取积分 <a class="header-anchor" href="#_2-完善信息领取积分" aria-label="Permalink to &quot;2. 完善信息领取积分&quot;">​</a></h3><p>注册完成后，进入会员中心补全 <strong>个人基础信息 → 项目环境与偏好 → 学术身份</strong>，提交后即可获得 <strong>100 积分</strong> 奖励，用于后续兑换算力券。</p><div align="center"><img src="'+d+'" alt="完善信息获取 100 积分"></div><h3 id="_3-进入云算力-创建工作区" tabindex="-1">3. 进入云算力 / 创建工作区 <a class="header-anchor" href="#_3-进入云算力-创建工作区" aria-label="Permalink to &quot;3. 进入云算力 / 创建工作区&quot;">​</a></h3><p>登录后在中文站首页一键进入 <strong>AMD 开发者云（Radeon Cloud）</strong>：</p><div align="center"><img src="'+h+'" alt="一键进入 Radeon Cloud"></div><ul><li>活动期间，注册成员<strong>免费获得 100 小时中国区专属算力额度</strong></li><li>平台底层基于 <strong>AMD Radeon PRO W7900D</strong> 等专业级 GPU</li><li>提供<strong>开箱即用的技术模板与工作区</strong>，无需自行配置 ROCm / PyTorch 环境</li><li>直接选择模板 → 启动工作区 → 在浏览器内进入开发环境</li></ul><div align="center"><img src="'+g+'" alt="Radeon Cloud 工作区与技术模板"></div><h3 id="_4-算力扩展-积分兑换-魔搭联动" tabindex="-1">4. 算力扩展：积分兑换 + 魔搭联动 <a class="header-anchor" href="#_4-算力扩展-积分兑换-魔搭联动" aria-label="Permalink to &quot;4. 算力扩展：积分兑换 + 魔搭联动&quot;">​</a></h3><p>如果初始 100 小时不够用，有两条扩展路径：</p><h4 id="路径-a-积分兑换算力券" tabindex="-1">路径 A：积分兑换算力券 <a class="header-anchor" href="#路径-a-积分兑换算力券" aria-label="Permalink to &quot;路径 A：积分兑换算力券&quot;">​</a></h4><p>中文站采用透明的积分成长规则，开发者可通过技术贡献多维度积累积分，<strong>积分等额兑换云算力券</strong>——边沉淀技术能力边累积算力资源。</p><div align="center"><img src="'+c+'" alt="积分等额兑换云算力券"></div><h4 id="路径-b-魔搭社区「开发者激励计划」" tabindex="-1">路径 B：魔搭社区「开发者激励计划」 <a class="header-anchor" href="#路径-b-魔搭社区「开发者激励计划」" aria-label="Permalink to &quot;路径 B：魔搭社区「开发者激励计划」&quot;">​</a></h4><p>AMD 与魔搭社区联合启动激励计划，提供 <strong>3 条完全独立的进阶任务路径</strong>，灵活叠加最高可累计获得 <strong>1000+ 小时</strong> GPU 算力：</p><ol><li>通过魔搭 Notebook 活动页进入</li><li>授权绑定 AMD 开发者计划账号（即完成上述注册步骤）</li><li>完成对应进阶任务即可解锁算力</li></ol><div align="center"><img src="'+m+'" alt="魔搭联动三条进阶任务路径"></div><blockquote><p>📌 详情参见 AMD AI 开发者计划中文站公告。</p></blockquote><h4 id="积分兑换" tabindex="-1">积分兑换 <a class="header-anchor" href="#积分兑换" aria-label="Permalink to &quot;积分兑换&quot;">​</a></h4><p>积分兑换的完整逻辑是：先在 <strong>AMD AI 开发者计划中文站</strong>消耗积分生成云算力券链接，再前往 <strong>AMD 开发者云平台</strong>完成兑换入账。</p><div align="center"><img src="'+p+'" alt="兑换入口"></div><div align="center"><img src="'+u+'" alt="兑换入口"></div><h5 id="兑换规则" tabindex="-1">兑换规则 <a class="header-anchor" href="#兑换规则" aria-label="Permalink to &quot;兑换规则&quot;">​</a></h5><ul><li><strong>兑换比例</strong>：1 积分可兑换 1 小时 AMD GPU 云算力</li><li><strong>起兑门槛</strong>：100 积分起兑，兑换小时数不超过当前剩余可兑换积分数</li><li><strong>兑换结果</strong>：兑换成功后会生成虚拟云算力券 / 兑换链接</li><li><strong>使用方式</strong>：复制兑换链接后，需要前往 AMD 开发者云平台完成入账</li><li><strong>有效期</strong>：云算力券通常自兑换日起 30 天内有效，请及时使用</li><li><strong>注意事项</strong>：兑换的是线上云算力服务，不是实物或现金；请勿转售或违规获取积分</li></ul><div align="center"><img src="'+f+'" alt="兑换规则"></div><h5 id="兑换流程" tabindex="-1">兑换流程 <a class="header-anchor" href="#兑换流程" aria-label="Permalink to &quot;兑换流程&quot;">​</a></h5><ol><li>从中文站主页面或活动入口进入云算力兑换区域</li><li>在兑换活动页点击 <strong>立即兑换</strong></li><li>输入想兑换的云算力小时数，点击 <strong>去兑换</strong></li><li>兑换成功后复制生成的兑换链接</li><li>访问 <strong>AMD 开发者云平台</strong></li><li>使用 GitHub 或魔搭账号登录，并完成账号授权</li><li>点击右上角头像进入 <strong>Profile</strong></li><li>点击 <strong>Redeem Credits</strong></li><li>在 <strong>Coupon Link</strong> 输入框粘贴兑换链接，点击 <strong>Redeem</strong> 完成兑换</li></ol><h3 id="_5-跑通你的第一个-rocm-任务" tabindex="-1">5. 跑通你的第一个 ROCm 任务 <a class="header-anchor" href="#_5-跑通你的第一个-rocm-任务" aria-label="Permalink to &quot;5. 跑通你的第一个 ROCm 任务&quot;">​</a></h3><p>平台预置了开箱即用的环境，建议起步路径：</p><ol><li>启动一个内置 ROCm + PyTorch 模板的工作区</li><li>参考本仓库 <a href="/hello-rocm/zh/01-deploy/">Gemma4 部署教程</a> 跑通推理</li><li>进入 <a href="/hello-rocm/zh/02-fine-tune/">LoRA 微调实战</a> 体验训练</li><li>进阶 <a href="/hello-rocm/zh/03-infra/">算子优化</a> 了解底层</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q1：完全免费吗？</strong> 活动期间注册即送 100 小时中国区专属算力。后续可通过积分兑换或魔搭激励计划继续扩展。</p><p><strong>Q2：需要科学上网吗？</strong> 不需要。中文站本地化部署，访问与登录均针对中国网络环境优化。</p><p><strong>Q3：可以用本仓库的教程吗？</strong> 可以。平台内置 ROCm + PyTorch 等常见模板，本仓库 <code>01-deploy</code> / <code>02-fine-tune</code> / <code>03-infra</code> 的教程可直接在工作区内运行。</p><p><strong>Q4：遇到 ROCm 软件栈或硬件适配问题怎么办？</strong> 加入「中国成员专属技术支持微信群」，AMD 官方技术支持团队会随群协助解答。入口在中文站个人中心。</p><p><strong>Q5：100 小时用完后怎么办？</strong></p><ul><li>走积分兑换路径：完善贡献、参与活动累积积分，兑换算力券</li><li>走魔搭路径：完成「开发者激励计划」3 条独立任务路径，最高 1000+ 小时</li><li>详见上面「算力扩展」小节</li></ul><h2 id="配套教程对应关系" tabindex="-1">配套教程对应关系 <a class="header-anchor" href="#配套教程对应关系" aria-label="Permalink to &quot;配套教程对应关系&quot;">​</a></h2><blockquote><p>本仓库哪些教程可以直接在 AMD Radeon Cloud 上运行：</p></blockquote><table tabindex="0"><thead><tr><th>学习阶段</th><th>对应教程</th><th>推荐工作区模板</th></tr></thead><tbody><tr><td>大模型部署</td><td><a href="/hello-rocm/zh/01-deploy/">Gemma 4 / Qwen3 / Qwen3.5 部署</a></td><td>ROCm + PyTorch</td></tr><tr><td>LoRA 微调</td><td><a href="/hello-rocm/zh/02-fine-tune/">Gemma4-E4B LoRA 微调</a></td><td>ROCm + PyTorch + Transformers</td></tr><tr><td>算子优化</td><td><a href="/hello-rocm/zh/03-infra/">ROCm 算子优化实践</a></td><td>ROCm + HIP 开发环境</td></tr><tr><td>组队学习</td><td><a href="/hello-rocm/zh/learning/">hello-rocm 组队学习</a></td><td>由 Datawhale 组队营提供</td></tr></tbody></table><hr><p>返回：<a href="/hello-rocm/zh/">← hello-rocm 首页</a></p>',61)])])}const z=o(A,[["render",b]]);export{v as __pageData,z as default};
